import os
from google.cloud import storage
from keras.models import load_model

# Function to fetch and load latest model version
def load_latest_model(bucket_name, model_path):
    # Define the client
    client = storage.Client()
    
    # Access the bucket
    bucket = client.get_bucket(bucket_name)
    
    # List all blobs in the bucket that matches the given prefix
    blobs = bucket.list_blobs(prefix=model_path)
    
    # Sort blobs by modification time and get latest version
    sorted_blobs = sorted(blobs, key=lambda x: x.updated, reverse=True)
    latest_blob = sorted_blobs[0]
    
    # Download the latest model file
    temp_file_name = 'temp.h5'
    bucket.download_blob_to_file(latest_blob, temp_file_name)
    
    # Load the downloaded model
    model = load_model(temp_file_name)
    
    # Remove temporary file
    os.remove(temp_file_name)
    
    return model

# Get bucket and model path from environment variables
bucket_name = os.environ['BUCKET_NAME']
model_path = os.environ['MODEL_PATH']

# Load the latest model version on startup
model = load_latest_model(bucket_name, model_path)